package be.schaubroeck.lpb.rkm.rekenmotor.datamanager;

import be.schaubroeck.lpb.rkm.corehr.config.RekenmotorCoreHrClient;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext;
import be.schaubroeck.lpb.rkm.rekenmotor.cache.CachedService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.Constant;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.AkeTijdperk;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.model.AfwezigheidBO;
import be.schaubroeck.lpb.tools.service.AardKodeExtensieService;
import be.schaubroeck.lpb.tools.service.ConstantService;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import be.schaubroeck.temporal.interval.Month;
import com.google.common.collect.ImmutableMap;
import com.google.common.collect.Ordering;
import org.joda.time.LocalDate;
import org.springframework.stereotype.Component;

import java.util.HashSet;
import java.util.Map;
import java.util.Set;

@Component
public class DataUitInvoerModule implements CachedService {
    private static final ThreadLocal<CachedDataUitInvoerModuleBuffer> BUFFER = new ThreadLocal<>();

    private final RekenmotorCoreHrClient rekenmotorCoreHrClient;
    private final AardKodeExtensieService aardKodeExtensieService;
    private final ConstantService constantService;

    public DataUitInvoerModule(AardKodeExtensieService aardKodeExtensieService, ConstantService constantService, RekenmotorCoreHrClient rekenmotorCoreHrClient) {
        CacheContext.getInstance().registerCachedServices(this, CacheContext.Scope.ADMIN);
        this.aardKodeExtensieService = aardKodeExtensieService;
        this.constantService = constantService;
        this.rekenmotorCoreHrClient = rekenmotorCoreHrClient;
    }

    public void bepaal(Admin admin, RekenTijd rekenTijd, PersoonsDataManagerImp dataManager, RegulManager regulManager) {
        Persoon persoon = dataManager.getPersoonOpDatum(rekenTijd.eindDatum);
        boolean isCoreHrKlant = isCoreHrKlant(admin, rekenTijd);
        if (isCoreHrKlant) {
            ImmutableMap<Integer, OvereenkomstRkmBO> overeenkomstBoMap = getDataUitInvoerModule(admin, persoon, rekenTijd, regulManager);
            for (Opdracht opdracht : persoon.getOpdrachten()) {
                OvereenkomstRkmBO overeenkomst = overeenkomstBoMap.get(opdracht.getOpdrachtnr());
                bepaalOpdracht(rekenTijd.rekenPeriode, opdracht, overeenkomst);
            }
        } else {
            persoon.getOpdrachten().stream().map(Opdracht::getOpperSlices).flatMap(Set::stream).forEach(x -> x.setAfwezighedenInvoerModule(new HashSet<>()));
        }
    }

    public void bepaal(Admin admin, Opper opper, LocalDateInterval periode) {
        boolean isCoreHrKlant = isCoreHrKlant(admin, periode.getStart());
        if (isCoreHrKlant) {
            Persoon persoon = opper.getOpdracht().getPersoon();
            Opdracht opdracht = opper.getOpdracht();
            DataUitInvoerModuleMapBO dataUitInvoerModuleMapBO = bepaalDataUitInvoerModuleMap(admin, persoon, periode);
            OvereenkomstRkmBO overeenkomst = dataUitInvoerModuleMapBO.getOvereenkomstMap().get(opdracht.getOpdrachtnr());
            fillOpper(opper, periode, overeenkomst);
        } else {
            opper.setAfwezighedenInvoerModule(new HashSet<>());
        }
    }

    public void bepaalOpdracht(Admin admin, LocalDateInterval periode, Opdracht opdracht) {
        boolean isCoreHrKlant = isCoreHrKlant(admin, periode.getStart());
        if (isCoreHrKlant) {
            Map<Integer, OvereenkomstRkmBO> overeenkomstDtoMap =
                    bepaalDataUitInvoerModuleMap(admin, opdracht.getPersoon(), periode).getOvereenkomstMap();
            OvereenkomstRkmBO overeenkomstBo = overeenkomstDtoMap.get(opdracht.getOpdrachtnr());
            bepaalOpdracht(new Month(periode.getStart()), opdracht, overeenkomstBo);
        } else {
            opdracht.getOpperSlices().forEach(x -> x.setAfwezighedenInvoerModule(new HashSet<>()));
        }
    }

    public void bepaalOpdracht(LocalDateInterval periode, Opdracht opdracht, OvereenkomstRkmBO overeenkomst) {
        for (Opper opper : opdracht.getOpperSlices()) {
            fillOpper(opper, periode, overeenkomst);
        }
    }

    public void fillOpper(Opper opper, LocalDateInterval periode, OvereenkomstRkmBO overeenkomst) {
        LocalDate selectieDatum = Ordering.natural().min(opper.getActualTo(), periode.getEnd());
        OvereenkomstRkmAlgemeenBO overeenkomstAlgemeen = findOvereenkomstAlgemeenDTO(overeenkomst, selectieDatum);

        if (overeenkomstAlgemeen != null) {
            opper.setAfwezighedenInvoerModule(bepaalAfwezigheidBO(overeenkomstAlgemeen));
            opper.setOvereenkomst(overeenkomstAlgemeen.getAlgemeen());
        } else {
            opper.setAfwezighedenInvoerModule(new HashSet<>());
        }
        OvereenkomstRkmWeddeBO overeenkomstWedde = findOvereenkomstWeddeDTO(overeenkomst, selectieDatum);
        if (overeenkomstWedde != null) {
            opper.getBasisJaarWedde().setAfwijkendeIndexFederaal(Boolean.TRUE.equals(overeenkomstWedde.getAfwijkendeIndexFederaal()));
        } else {
            opper.getBasisJaarWedde().setAfwijkendeIndexFederaal(false);
        }
    }


    public ImmutableMap<Integer, OvereenkomstRkmBO> getDataUitInvoerModule(
            Admin admin, Persoon persoon, RekenTijd rekenTijd, RegulManager regulManager) {
        DataUitInvoerModuleMapBO mapping = bepaalDataUitInvoerModuleMap(admin, persoon, rekenTijd.rekenPeriode);
        if (mapping.isOutOfSync()) {
            regulManager.addRegul(rekenTijd.beginDatum, null, Regulkode.OUT_OF_SYNC_PERSOON);
        }
        return mapping.getOvereenkomstMap();
    }

    private boolean isCoreHrKlant(Admin admin, RekenTijd rekenTijd) {
        Constant startDatumCoreHr = constantService.getByCodeDatum(admin, Konstanten.KST_STARTDATUM_CORE_HR, rekenTijd.rekenDatum);
        return startDatumCoreHr != null && !rekenTijd.beginDatum.isBefore(startDatumCoreHr.getDatum());
    }

    private boolean isCoreHrKlant(Admin admin, LocalDate selectieDatum) {
        Constant startDatumCoreHr = constantService.getByCodeDatum(admin, Konstanten.KST_STARTDATUM_CORE_HR, selectieDatum);
        return startDatumCoreHr != null && !selectieDatum.isBefore(startDatumCoreHr.getDatum());
    }

    private OvereenkomstRkmAlgemeenBO findOvereenkomstAlgemeenDTO(OvereenkomstRkmBO overeenkomst, LocalDate selectieDatum) {
        OvereenkomstRkmAlgemeenBO overeenkomstAlgemeen = null;
        if (overeenkomst != null) {
            overeenkomstAlgemeen = overeenkomst.getAlgemeen().stream().filter(x -> x.contains(selectieDatum)).findAny().orElse(null);
        }
        return overeenkomstAlgemeen;
    }

    private OvereenkomstRkmWeddeBO findOvereenkomstWeddeDTO(OvereenkomstRkmBO overeenkomst, LocalDate selectieDatum) {
        OvereenkomstRkmWeddeBO overeenkomstWedde = null;
        if (overeenkomst != null) {
            overeenkomstWedde = overeenkomst.getWedde().stream().filter(x -> x.contains(selectieDatum)).findAny().orElse(null);
        }
        return overeenkomstWedde;
    }

    private Set<AfwezigheidBO> bepaalAfwezigheidBO(OvereenkomstRkmAlgemeenBO overeenkomstAlgemeen) {
        if (overeenkomstAlgemeen != null) {
            Set<AfwezigheidBO> afwezigheden = new HashSet<>();
            for (AfwezigheidRkmBO afwezigheidDto : overeenkomstAlgemeen.getAfwezigheden()) {
                AardKodeExtensie aardKodeExtensie =
                        aardKodeExtensieService.getAkeByTijdperkAardCodeExtensie(AkeTijdperk.DMFAPPL.getCode(), afwezigheidDto.getAard(), afwezigheidDto.getCode(),
                                afwezigheidDto.getExtensie());
                afwezigheden.add(new AfwezigheidBO(aardKodeExtensie, afwezigheidDto.getHours(), afwezigheidDto.getPeriod()));
            }
            return afwezigheden;
        } else {
            return new HashSet<>();
        }
    }


    public DataUitInvoerModuleMapBO bepaalDataUitInvoerModuleMap(Admin admin, Persoon persoon, LocalDateInterval rekenPeriode) {
        return getBuffer().getMapping(admin, persoon.getPersoneelsNr(), rekenPeriode, rekenmotorCoreHrClient);
    }

    private static CachedDataUitInvoerModuleBuffer getBuffer() {
        CachedDataUitInvoerModuleBuffer returnValue = BUFFER.get();
        if (returnValue == null) {
            returnValue = new CachedDataUitInvoerModuleBuffer();
            BUFFER.set(returnValue);
        }
        return returnValue;
    }

    @Override
    public void clearCache() {
        BUFFER.remove();
    }


}
